def canConvertString(s: str, t: str, k: int) -> bool:
    n = len(s)
    m = len(t)
    dp = [[False]*(m+1) for _ in range(n+1)]
    for i in range(1, n+1):
        for j in range(1, m+1):
            if s[i-1] == t[j-1]:
                dp[i][j] = dp[i-1][j-1] or dp[i-1][j]
            else:
                dp[i][j] = False
    return dp[n][m]

